70	    const result = runScenario({
71	      customer: { yearsWithMHPCO: 0 },
72	      steps: [{
73	        op: "quote",
74	        items: Array.from({ length: 7 }, () => ({ type: "rune" })),
75	      }],
76	    });
77	    expect(result).toEqual({ results: [{ premium: 198 }] });
78	  });
79	
80	  // === Alike components: same type only ===
81	  it("2 runes + 1 moonstone → 75 G base premium → +10% first +5 fee = 88 G", () => {
82	    const result = runScenario({
83	      customer: { yearsWithMHPCO: 0 },
84	      steps: [{
85	        op: "quote",
86	        items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
87	      }],
88	    });
89	    expect(result).toEqual({ results: [{ premium: 88 }] });
90	  });
91	  it("3 runes + 3 moonstones → 120 G base premium (two separate blocks) → +10% first +5 fee = 137 G", () => {
92	    const result = runScenario({
93	      customer: { yearsWithMHPCO: 0 },
94	      steps: [{
95	        op: "quote",
96	        items: [
97	          { type: "rune" }, { type: "rune" }, { type: "rune" },
98	          { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
99	        ],
100	      }],
101	    });
102	    expect(result).toEqual({ results: [{ premium: 137 }] });
103	  });
104	
105	  // === Cursed surcharge ===
106	  it("cursed sword (newcomer, first contract) → 100+50+15 first +5 fee = 170 G", () => {
107	    const result = runScenario({
108	      customer: { yearsWithMHPCO: 0 },
109	      steps: [{ op: "quote", items: [{ type: "sword", cursed: true }] }],
110	    });
111	    expect(result).toEqual({ results: [{ premium: 170 }] });
112	  });
113	
114	  // === Modifier scope: per-item surcharges vs policy-wide modifiers ===
115	  it.todo("cursed sword + plain amulet → base 160 + 50 curse (on sword only) = 210 G before further modifiers and fee");
116	
117	  // === High-enchantment surcharge ===
118	  it.todo("sword with enchantment 5 (newcomer, first contract) → 100+30+13 first +5 fee = 148 G");
119	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
120	  it.todo("sword with enchantment 5 AND cursed → both surcharges apply");
121	
122	  // === Loyalty discount ===
123	  it.todo("customer with exactly 2 years → loyalty discount applies (20%)");
124	
125	  // === Rounding in MHPCO's favor ===
126	  it.todo("premium calculation yielding 197.5 G → 198 G (rounded up)");
127	  it.todo("payout calculation yielding 350.5 G → 350 G (rounded down)");
128	
129	  // === Integration: Newcomer with cursed sword ===
130	  it.todo("newcomer (0 years, first contract), cursed sword (steel, ench 3) → premium 165 G");
131	
132	  // === Integration: Long-standing customer's 2nd contract ===
133	  it.todo("3 years customer, 2nd quote, cursed sword (steel, ench 7) → premium 160 G");
134	
135	  // === Follow-up contract discount: each item still treated as first insurance ===
136	  it.todo("follow-up contract: first-insurance surcharge still applies per item");
137	
138	  // === Claim: standard reimbursement ===
139	  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (500 - 100 deductible)");
140	  it.todo("damage to a rune (value 250), damage 200 G → payout 100 G (200 - 100 deductible)");
141	
142	  // === Claim: deductible per item ===
143	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible per item)");
144	
145	  // === Claim: high-enchantment clause ===
146	  it.todo("steel sword, ench 9, damage 1000 → payout 400 (50% then deductible)");
147	
148	  // === Claim: dragon material clause ===
149	  it.todo("dragon sword, ench 5, damage 800 → payout 700 (full then deductible)");
150	
151	  // === Claim: both clauses → 50% wins ===
152	  it.todo("dragon sword, ench 9, damage 1000 → payout 400 (50% wins, then deductible)");
153	  it.todo("dragon sword, ench exactly 8, damage 1000 → payout 400 (high-ench applies, then deductible)");
154	
155	  // === Cap exhaustion ===
156	  it.todo("sword (1000), cap 2000; first claim 1500 → payout 1400, remainingCap 600");
157	  it.todo("sword (1000), cap 2000; first claim 1500 (payout 1400), second claim 1500 → payout 600, remainingCap 0");
158	
159	  // === Insurance sum / cap calculation ===
160	  it.todo("policy with sword + amulet → insurance sum 1600, cap 3200");
161	  it.todo("cursed sword → cap 2000 (modifiers do not raise cap)");
162	  it.todo("sword + 3 runes (block) → insurance sum 1750 (block affects premium, not sum)");
163	
164	  // === Multiple items of same type ===
165	  it.todo("policy covers two swords → insurance sum 2000, cap 4000");
166	  it.todo("dragon attack damages both swords (two entries) → each entry has its own deductible");
167	  it.todo("damages array contains more entries than policy covers → CLI exits non-zero");
168	
169	  // === Edge cases ===
170	  it.todo("quote with unknown item type → CLI exits non-zero, error on stderr");
171	  it.todo("claim damages references item not in policy → CLI exits non-zero, stderr error");
172	  it.todo("claim with damage amount -200 → CLI exits non-zero, stderr error");
173	});
