1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	type Item = { type: string; cursed?: boolean };
14	const CURSE_SURCHARGE = 0.5;
15	type QuoteStep = { op: "quote"; items: Item[] };
16	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
17	type QuoteResult = { premium: number };
18	
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const BLOCK_SIZE = 3;
21	const BLOCK_PREMIUM = 60;
22	
23	const isBlock = (type: string, count: number): boolean =>
24	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
25	
26	const groupPremium = (type: string, count: number): number =>
27	  isBlock(type, count) ? BLOCK_PREMIUM : BASE_PREMIUM[type] * count;
28	
29	const countByType = (items: Item[]): Map<string, number> => {
30	  const counts = new Map<string, number>();
31	  for (const { type } of items) counts.set(type, (counts.get(type) ?? 0) + 1);
32	  return counts;
33	};
34	
35	const basePremiumForItems = (items: Item[]): number =>
36	  [...countByType(items)].reduce(
37	    (total, [type, count]) => total + groupPremium(type, count),
38	    0,
39	  );
40	
41	const curseSurchargeForItems = (items: Item[]): number =>
42	  items.reduce(
43	    (total, item) =>
44	      total + (item.cursed ? BASE_PREMIUM[item.type] * CURSE_SURCHARGE : 0),
45	    0,
46	  );
47	
48	const withFirstInsuranceSurcharge = (amount: number): number =>
49	  amount + amount * FIRST_INSURANCE_SURCHARGE;
50	
51	const quotePremium = ({ items }: QuoteStep): QuoteResult => {
52	  const basePremium = basePremiumForItems(items) + curseSurchargeForItems(items);
53	  const withSurcharge = withFirstInsuranceSurcharge(basePremium);
54	  return { premium: Math.ceil(withSurcharge + PROCESSING_FEE) };
55	};
56	
57	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => ({
58	  results: scenario.steps.map(quotePremium),
59	});
60

